+@page "/calendar"
+@rendermode InteractiveServer
+@inject ICalendarService CalendarService
+
+<PageTitle>Team Calendar</PageTitle>
+
+<div class="calendar-container">
+    <!-- Month Navigation Bar -->
+    <div class="calendar-nav">
+        <button class="btn btn-outline-secondary" @onclick="PreviousMonth">Previous</button>
+        <button class="btn btn-outline-primary" @onclick="GoToToday">Today</button>
+        <h3 class="month-label">@currentDate.ToString("MMMM yyyy")</h3>
+        <button class="btn btn-outline-secondary" @onclick="NextMonth">Next</button>
+    </div>
+
+    <!-- Team Member Filter -->
+    <div class="team-filter">
+        <button class="btn btn-sm btn-link" @onclick="ToggleSelectAll">
+            @(selectedMembers.Count == teamMembers.Count ? "Deselect All" : "Select All")
+        </button>
+        @foreach (var member in teamMembers)
+        {
+            <label class="filter-checkbox">
+                <input type="checkbox" checked="@selectedMembers.Contains(member)"
+                       @onchange="e => ToggleMember(member, (bool)e.Value!)" />
+                @member
+            </label>
+        }
+    </div>
+
+    <div class="calendar-body">
+        <!-- Calendar Grid -->
+        <div class="calendar-grid">
+            <div class="day-header">Mon</div>
+            <div class="day-header">Tue</div>
+            <div class="day-header">Wed</div>
+            <div class="day-header">Thu</div>
+            <div class="day-header">Fri</div>
+            <div class="day-header">Sat</div>
+            <div class="day-header">Sun</div>
+
+            @foreach (var day in calendarDays)
+            {
+                var dayCopy = day;
+                var cellClass = GetDayCellClass(dayCopy);
+                var dayEvents = GetFilteredEventsForDay(dayCopy);
+                <div class="@cellClass" @onclick="() => SelectDay(dayCopy)">
+                    <span class="day-number">@dayCopy.Day</span>
+                    @if (dayEvents.Count > 0)
+                    {
+                        <div class="event-dots">
+                            @for (int i = 0; i < Math.Min(dayEvents.Count, 3); i++)
+                            {
+                                <span class="event-dot"></span>
+                            }
+                            @if (dayEvents.Count > 3)
+                            {
+                                <span class="more-events">+@(dayEvents.Count - 3) more</span>
+                            }
+                        </div>
+                    }
+                </div>
+            }
+        </div>
+
+        <!-- Day Detail Side Panel -->
+        @if (selectedDay.HasValue)
+        {
+            <div class="day-panel">
+                @if (!showNewEventForm)
+                {
+                    <h4>@selectedDay.Value.ToString("dddd, MMMM d, yyyy")</h4>
+
+                    @{ var selectedDayEvents = GetFilteredEventsForDay(selectedDay.Value); }
+
+                    @if (selectedDayEvents.Count == 0)
+                    {
+                        <p class="no-events">No events scheduled</p>
+                    }
+                    else
+                    {
+                        <ul class="event-list">
+                            @foreach (var evt in selectedDayEvents)
+                            {
+                                <li class="event-item">
+                                    <div class="event-title">@evt.Title</div>
+                                    <div class="event-time">@FormatTime(evt.StartTime) – @FormatTime(evt.EndTime)</div>
+                                    <div class="event-attendees">@string.Join(", ", evt.Attendees)</div>
+                                    <button class="btn btn-sm btn-danger" @onclick="() => DeleteEvent(evt.Id)">Delete</button>
+                                </li>
+                            }
+                        </ul>
+                    }
+
+                    <button class="btn btn-primary mt-3" @onclick="ShowNewEventForm">New Event</button>
+                }
+                else
+                {
+                    <!-- New Event Form -->
+                    <h4>New Event</h4>
+                    <div class="new-event-form">
+                        <div class="mb-2">
+                            <label>Title</label>
+                            <input type="text" class="form-control" @bind="newEventTitle" />
+                        </div>
+                        <div class="mb-2">
+                            <label>Date</label>
+                            <input type="date" class="form-control" @bind="newEventDate" />
+                        </div>
+                        <div class="mb-2">
+                            <label>Start Time</label>
+                            <input type="time" class="form-control" @bind="newEventStartTime" />
+                        </div>
+                        <div class="mb-2">
+                            <label>End Time</label>
+                            <input type="time" class="form-control" @bind="newEventEndTime" />
+                        </div>
+                        <div class="mb-2">
+                            <label>Attendees</label>
+                            @foreach (var member in teamMembers)
+                            {
+                                <label class="filter-checkbox">
+                                    <input type="checkbox" checked="@newEventAttendees.Contains(member)"
+                                           @onchange="e => ToggleNewEventAttendee(member, (bool)e.Value!)" />
+                                    @member
+                                </label>
+                            }
+                        </div>
+                        <div class="form-buttons">
+                            <button class="btn btn-success" @onclick="SaveNewEvent">Save</button>
+                            <button class="btn btn-secondary" @onclick="CancelNewEvent">Cancel</button>
+                        </div>
+                    </div>
+                }
+            </div>
+        }
+    </div>
+</div>
